 fn parse_uuid_guarded(s: &str, context: &str) -> Option<Uuid> {
     match s.parse::<Uuid>() {
         Ok(uuid) => Some(uuid),
         Err(e) => {
             tracing::warn!(
                 context,
                 uuid_str = %s,
                 error = %e,
                 "Invalid UUID string - skipping operation to prevent NIL UUID corruption"
